API_name: nchu_teacher_search_by_department
Description:
{
  "description": "依系所搜尋中興大學教師。",
  "required_parameters": [
    {
      "name": "department",
      "type": "STRING",
      "description": "欲搜尋的系所名稱（支援部分比對）"
    }
  ],
  "optional_parameters": [
    {
      "name": "title",
      "type": "STRING",
      "description": "Optional title filter (e.g., \"教授\", \"副教授\", \"助理教授\")",
      "default": null
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 50）",
      "default": 50
    }
  ]
}

